import { useRouter } from 'expo-router';
import { Calendar, Clock, MessageCircle } from 'lucide-react-native';
import React, { useEffect, useState } from 'react';
import { ActivityIndicator, FlatList, StyleSheet, Text, TouchableOpacity, View } from 'react-native';
import { supabase } from '../../lib/supabase';

export default function MyBookingsScreen() {
    const [bookings, setBookings] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const router = useRouter();

    const fetchBookings = async () => {
        setLoading(true);
        try {
            const { data: { user } } = await supabase.auth.getUser();
            if (!user) return;

            const { data, error } = await supabase
                .from('bookings')
                .select(`
          *,
          service_providers (business_name)
        `)
                .eq('customer_id', user.id)
                .order('created_at', { ascending: false });

            if (error) throw error;
            setBookings(data || []);
        } catch (e) {
            console.error(e);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchBookings();
    }, []);

    const getStatusColor = (status: string) => {
        switch (status) {
            case 'requested': return '#F59E0B'; // Amber
            case 'confirmed': return '#0056FF'; // Blue
            case 'in_progress': return '#8B5CF6'; // Purple
            case 'completed': return '#10B981'; // Green
            case 'cancelled': return '#EF4444'; // Red
            default: return '#666';
        }
    };

    const renderItem = ({ item }: { item: any }) => (
        <View style={styles.card}>
            <View style={styles.cardHeader}>
                <View style={{ flex: 1 }}>
                    <Text style={styles.providerName}>{item.service_providers?.business_name || 'Provider'}</Text>
                    <Text style={[styles.statusText, { color: getStatusColor(item.status) }]}>
                        {item.status.toUpperCase().replace('_', ' ')}
                    </Text>
                </View>
                <Text style={styles.bookingId}>#{item.booking_number}</Text>
            </View>

            <View style={styles.infoRow}>
                <Calendar color="#666" size={16} />
                <Text style={styles.infoText}>{item.scheduled_date}</Text>
            </View>

            <View style={styles.infoRow}>
                <Clock color="#666" size={16} />
                <Text style={styles.infoText}>{item.scheduled_time_slot}</Text>
            </View>

            {/* Show Chat Button if Accepted/In Progress */}
            {['confirmed', 'in_progress'].includes(item.status) && (
                <TouchableOpacity
                    style={styles.chatButton}
                    onPress={() => router.push({ pathname: '/chat/[id]', params: { id: item.id } } as any)}
                >
                    <MessageCircle color="#0056FF" size={20} />
                    <Text style={styles.chatButtonText}>Chat with Provider</Text>
                </TouchableOpacity>
            )}
        </View>
    );

    return (
        <View style={styles.container}>
            <View style={styles.header}>
                <Text style={styles.title}>My Bookings</Text>
            </View>

            {loading ? (
                <ActivityIndicator style={styles.loader} size="large" color="#0056FF" />
            ) : (
                <FlatList
                    data={bookings}
                    keyExtractor={(item) => item.id}
                    renderItem={renderItem}
                    contentContainerStyle={styles.list}
                    ListEmptyComponent={
                        <View style={styles.emptyContainer}>
                            <Text style={styles.emptyText}>You haven't requested any services yet.</Text>
                        </View>
                    }
                    refreshing={loading}
                    onRefresh={fetchBookings}
                />
            )}
        </View>
    );
}

const styles = StyleSheet.create({
    container: {
        flex: 1,
        backgroundColor: '#F8F9FA',
    },
    header: {
        paddingTop: 60,
        paddingHorizontal: 20,
        paddingBottom: 20,
        backgroundColor: '#FFF',
        borderBottomWidth: 1,
        borderBottomColor: '#E0E0E0',
    },
    title: {
        fontSize: 28,
        fontWeight: 'bold',
        color: '#111',
    },
    loader: {
        marginTop: 40,
    },
    list: {
        padding: 20,
        paddingBottom: 40,
    },
    card: {
        backgroundColor: '#FFF',
        borderRadius: 16,
        padding: 20,
        marginBottom: 16,
        shadowColor: '#000',
        shadowOffset: { width: 0, height: 2 },
        shadowOpacity: 0.05,
        shadowRadius: 8,
        elevation: 2,
        borderWidth: 1,
        borderColor: '#E0E0E0',
    },
    cardHeader: {
        flexDirection: 'row',
        justifyContent: 'space-between',
        alignItems: 'flex-start',
        marginBottom: 16,
        paddingBottom: 16,
        borderBottomWidth: 1,
        borderBottomColor: '#F0F0F0'
    },
    providerName: {
        fontSize: 18,
        fontWeight: 'bold',
        color: '#111',
        marginBottom: 4,
    },
    bookingId: {
        fontSize: 12,
        color: '#999',
        fontFamily: 'monospace',
    },
    statusText: {
        fontSize: 12,
        fontWeight: 'bold',
    },
    infoRow: {
        flexDirection: 'row',
        alignItems: 'flex-start',
        marginBottom: 12,
    },
    infoText: {
        fontSize: 14,
        color: '#555',
        marginLeft: 10,
        flex: 1,
    },
    chatButton: {
        flexDirection: 'row',
        alignItems: 'center',
        justifyContent: 'center',
        backgroundColor: '#E3F2FD',
        height: 48,
        borderRadius: 12,
        marginTop: 12,
    },
    chatButtonText: {
        color: '#0056FF',
        fontSize: 16,
        fontWeight: '600',
        marginLeft: 8,
    },
    emptyContainer: {
        alignItems: 'center',
        marginTop: 60,
    },
    emptyText: {
        fontSize: 16,
        color: '#999',
    }
});

import { useRouter } from 'expo-router';
import { MapPin, Search, Star } from 'lucide-react-native';
import React, { useEffect, useState } from 'react';
import { FlatList, Image, StyleSheet, Text, TextInput, TouchableOpacity, View } from 'react-native';
import { supabase } from '../../lib/supabase';

export default function SearchScreen() {
    const [query, setQuery] = useState('');
    const [providers, setProviders] = useState<any[]>([]);
    const [loading, setLoading] = useState(false);
    const router = useRouter();

    // Advanced Postgres search via RPC
    const searchProviders = async () => {
        setLoading(true);
        // Defaulting customer location to Varanasi for MVP until we get device location matching PostGIS
        const { data, error } = await supabase.rpc('search_providers_by_catalog_and_location', {
            search_query: query,
            customer_lat: 25.3176,
            customer_lng: 82.9739,
            max_distance_km: 50.0
        });

        if (data && !error) setProviders(data);
        setLoading(false);
    };

    useEffect(() => {
        if (query.length > 2) {
            searchProviders();
        }
    }, [query]);

    const renderItem = ({ item }: { item: any }) => (
        <TouchableOpacity
            style={styles.card}
            onPress={() => router.push({ pathname: '/provider/[id]', params: { id: item.user_id } } as any)}
        >
            <View style={styles.avatarContainer}>
                {item.avatar_url ? (
                    <Image source={{ uri: item.avatar_url }} style={styles.avatar} />
                ) : (
                    <View style={[styles.avatar, styles.avatarPlaceholder]}>
                        <Text style={styles.avatarText}>{item.business_name.charAt(0)}</Text>
                    </View>
                )}
            </View>
            <View style={styles.infoContainer}>
                <Text style={styles.name}>{item.business_name}</Text>
                {item.matched_service && (
                    <Text style={styles.matchedService}>Matches: {item.matched_service}</Text>
                )}
                <View style={styles.statsRow}>
                    <Star color="#F59E0B" size={14} fill="#F59E0B" />
                    <Text style={styles.rating}>{item.avg_rating.toFixed(1)}</Text>
                    <Text style={styles.jobs}>({item.total_jobs_completed} jobs)</Text>
                    <Text style={styles.distanceText}> ΓÇó {item.distance_km.toFixed(1)} km away</Text>
                </View>
                <View style={styles.locationRow}>
                    <MapPin color="#666" size={14} />
                    <Text style={styles.locationText}>
                        {item.city || 'Unknown'}, {item.pincode}
                    </Text>
                </View>
            </View>
        </TouchableOpacity>
    );

    return (
        <View style={styles.container}>
            <View style={styles.header}>
                <Text style={styles.title}>Search Experts</Text>
                <View style={styles.searchContainer}>
                    <Search color="#999" size={20} style={styles.searchIcon} />
                    <TextInput
                        style={styles.searchInput}
                        placeholder="Search by name or service..."
                        value={query}
                        onChangeText={setQuery}
                        autoFocus
                    />
                </View>
            </View>

            <FlatList
                data={providers}
                keyExtractor={(item) => item.user_id}
                renderItem={renderItem}
                contentContainerStyle={styles.listContent}
                ListEmptyComponent={
                    !loading && query.length > 2 ? (
                        <Text style={styles.emptyText}>No providers found.</Text>
                    ) : null
                }
            />
        </View>
    );
}

