import { useRouter } from 'expo-router';
import { Calendar, ChevronRight, MessageSquare, Search } from 'lucide-react-native';
import React, { useState } from 'react';
import { Dimensions, StyleSheet, Text, TouchableOpacity, View } from 'react-native';

const { width } = Dimensions.get('window');

const SLIDES = [
    {
        id: 1,
        title: 'Find Trusted Experts',
        subtitle: 'Finding the Most Experienced and Trusted People to Help You',
        icon: <Search size={80} color="#0056FF" />,
    },
    {
        id: 2,
        title: 'Schedule Your Way',
        subtitle: 'Schedule your service at your perfect time',
        icon: <Calendar size={80} color="#0056FF" />,
    },
    {
        id: 3,
        title: 'Stay Connected',
        subtitle: 'Chat or call your tasker to fine-tune every detail',
        icon: <MessageSquare size={80} color="#0056FF" />,
    },
];

export default function OnboardingScreen() {
    const [currentSlide, setCurrentSlide] = useState(0);
    const router = useRouter();

    const handleNext = () => {
        if (currentSlide < SLIDES.length - 1) {
            setCurrentSlide(currentSlide + 1);
        } else {
            router.push('/location');
        }
    };

    const handleSkip = () => {
        router.push('/location');
    };

    const slide = SLIDES[currentSlide];

    return (
        <View style={styles.container}>
            <View style={styles.header}>
                <TouchableOpacity onPress={handleSkip} style={styles.skipButton}>
                    <Text style={styles.skipText}>Skip</Text>
                    <ChevronRight size={20} color="#333" />
                </TouchableOpacity>
            </View>

            <View style={styles.imageContainer}>
                {slide.icon}
            </View>

            <View style={styles.contentContainer}>
                <View style={styles.pagination}>
                    {SLIDES.map((_, index) => (
                        <View
                            key={index}
                            style={[
                                styles.dot,
                                currentSlide === index ? styles.activeDot : styles.inactiveDot,
                            ]}
                        />
                    ))}
                </View>

                <Text style={styles.title}>{slide.title}</Text>
                <Text style={styles.subtitle}>{slide.subtitle}</Text>

                <TouchableOpacity style={styles.nextButton} onPress={handleNext}>
                    <Text style={styles.nextButtonText}>
                        {currentSlide === SLIDES.length - 1 ? 'Get Started' : 'Next'}
                    </Text>
                </TouchableOpacity>
            </View>
        </View>
    );
}

