import { useLocalSearchParams, useRouter } from 'expo-router';
import { CheckCircle, ChevronLeft, Star } from 'lucide-react-native';
import React, { useEffect, useState } from 'react';
import { ActivityIndicator, Image, ScrollView, StyleSheet, Text, TouchableOpacity, View } from 'react-native';
import { supabase } from '../../lib/supabase';

export default function ProviderDetailScreen() {
    const { id } = useLocalSearchParams();
    const router = useRouter();
    const [provider, setProvider] = useState<any>(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        async function loadProvider() {
            const { data } = await supabase
                .from('service_providers')
                .select(`
          *,
          user_profiles (full_name, avatar_url, city, pincode),
          provider_services (
             base_price,
             hourly_rate,
             experience_years,
             service_subcategories (name, estimated_duration_minutes)
          )
        `)
                .eq('user_id', id)
                .single();

            if (data) setProvider(data);
            setLoading(false);
        }
        if (id) loadProvider();
    }, [id]);

    if (loading) {
        return (
            <View style={styles.centerContainer}>
                <ActivityIndicator size="large" color="#0056FF" />
            </View>
        );
    }

    if (!provider) {
        return (
            <View style={styles.centerContainer}>
                <Text>Provider not found.</Text>
            </View>
        );
    }

    return (
        <View style={styles.container}>
            {/* Header */}
            <View style={styles.header}>
                <TouchableOpacity style={styles.backButton} onPress={() => router.back()}>
                    <ChevronLeft color="#111" size={28} />
                </TouchableOpacity>
                <Text style={styles.headerTitle}>Expert Details</Text>
                <View style={{ width: 28 }} />
            </View>

            <ScrollView contentContainerStyle={styles.scrollContent}>

                {/* Profile Card */}
                <View style={styles.profileCard}>
                    <Image
                        source={{ uri: provider.user_profiles?.avatar_url || 'https://via.placeholder.com/100' }}
                        style={styles.avatar}
                    />
                    <Text style={styles.name}>{provider.business_name || provider.user_profiles?.full_name}</Text>

                    {provider.verification_status === 'verified' && (
                        <View style={styles.verifiedBadge}>
                            <CheckCircle color="#0056FF" size={16} />
                            <Text style={styles.verifiedText}>Workla Verified</Text>
                        </View>
                    )}

                    <View style={styles.statsRow}>
                        <View style={styles.statItem}>
                            <Star color="#F59E0B" size={20} fill="#F59E0B" />
                            <Text style={styles.statValue}>{provider.avg_rating.toFixed(1)}</Text>
                            <Text style={styles.statLabel}>Rating</Text>
                        </View>
                        <View style={styles.divider} />
                        <View style={styles.statItem}>
                            <Text style={styles.statValue}>{provider.total_jobs_completed}</Text>
                            <Text style={styles.statLabel}>Jobs Done</Text>
                        </View>
                        <View style={styles.divider} />
                        <View style={styles.statItem}>
                            <Text style={styles.statValue}>{provider.years_of_experience} yrs</Text>
                            <Text style={styles.statLabel}>Experience</Text>
                        </View>
                    </View>
                </View>

                {/* Services List */}
                <Text style={styles.sectionTitle}>Services Offered</Text>
                {provider.provider_services?.map((service: any, index: number) => (
                    <View key={index} style={styles.serviceCard}>
                        <View style={styles.serviceInfo}>
                            <Text style={styles.serviceName}>{service.service_subcategories?.name}</Text>
                            <Text style={styles.serviceDuration}>Est. {service.service_subcategories?.estimated_duration_minutes} mins</Text>
                        </View>
                        <View style={styles.servicePrice}>
                            <Text style={styles.priceAmount}>Γé╣{service.base_price}</Text>
                            <Text style={styles.priceType}>Base Price</Text>
                        </View>
                    </View>
                ))}

                {provider.provider_services?.length === 0 && (
                    <Text style={styles.emptyText}>This provider hasn't listed specific services yet.</Text>
                )}

            </ScrollView>

            {/* Bottom Booking Button */}
            <View style={styles.footer}>
